class Solution(object):
    def minXor(self, nums, k):
        n = len(nums)
        pre = [0] * (n + 1)
        for i in range(n):
            pre[i + 1] = pre[i] ^ nums[i]

        INF = float('inf')
        # dp[j][i] = min max-XOR splitting nums[0..i-1] into j parts
        dp = [[INF] * (n + 1) for _ in range(k + 1)]
        dp[0][0] = 0

        for j in range(1, k + 1):
            for i in range(j, n + 1):
                for t in range(j - 1, i):
                    if dp[j - 1][t] == INF:
                        continue
                    xor_val = pre[i] ^ pre[t]
                    dp[j][i] = min(dp[j][i], max(dp[j - 1][t], xor_val))

        return dp[k][n]
